      updateMatchingLists<CrmEmailMessage>(queryClient, [...crmKeys.all, 'emails'], id, values)
      return { previous }
    },
    onError: (_error, _vars, context) => {
      context?.previous.forEach(([key, data]) => queryClient.setQueryData(key, data))
